VALUES
  ('real-estate-moex-01034', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於添附，下列敘述，何者正確？', '["動產因附合而為不動產之重要成分者，動產及不動產所有人，共有該動產所有權", "動產與他人之動產附合，非毀損不能分離，或分離需費過鉅者，各動產所有人，按其動產附合時之比 例，比例高者取得合成物之所有權", "動產與他人之動產混合，不能識別，或識別需費過鉅者，拍賣之", "附合之動產，有可視為主物者，該主物所有人，取得合成物之所有權"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01035', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲將其單獨所有之土地的特定部分出售予乙後，如該土地無不可分割之限制時，乙得如何請求甲履行其 移轉所有權之義務？', '["請求甲移轉登記按該特定部分計算之土地應有部分，與甲共有該土地", "請求甲將該特定部分分割後移轉登記與乙", "乙得選擇請求甲為上述", "或"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01036', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲、乙、丙三人各有應有部分三分之一分別共有A地。下列敘述，何者正確？', '["甲得以其應有部分供第三人丁設定不動產役權", "三人協議分割達成合意之履行請求權，有消滅時效之適用", "甲須以共有人過半數及應有部分合計過半數之同意，始得請求分割", "甲得以共有人過半數及應有部分合計過半數之同意，以A地供丁設定抵押權"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01037', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '關於區分所有建築物，下列敘述，何者錯誤？', '["稱區分所有建築物者，謂數人區分一建築物而各專有其一部，就專有部分有單獨所有權，並就該建築 物及其附屬物之共同部分共有之建築物", "區分所有建築物共有部分，指區分所有建築物專有部分以外之其他部分及不屬於專有部分之附屬物", "區分所有建築物共有部分除法律另有規定外，不得經規約之約定，供區分所有建築物之特定所有人使用", "區分所有建築物專有部分得經其所有人之同意，依規約之約定，供區分所有建築物之所有人共同使用"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01038', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲以其土地設定不動產役權於乙後，復以同一土地之一部分設定普通地上權於丙。丙之普通地上權的效 力如何？', '["當然無效", "當然有效、且其效力優先於乙之不動產役權", "無妨害乙之不動產役權時，當然有效", "乙、丙各自之用益物權的優先效力，由所有權人甲決定之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01039', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲以A地設定抵押權於乙，擔保其對乙所負債務後，復將A地設定地上權於丙，由丙於A地上建築房屋。 甲屆期無力清償債務，乙實行對A地之抵押權時，抵押權人實行抵押權受有影響者。下列敘述，何者正確？', '["法院得除去丙之地上權，乙於必要時並得聲請法院將建築物與土地併付拍賣", "法院得除去丙之地上權，但乙僅得聲請法院拍賣土地", "法院不得除去丙之地上權，但乙於必要時，得聲請法院將地上權及建築物與土地併付拍賣", "法院不得除去丙之地上權，乙僅得聲請法院拍賣土地"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 30, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01040', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '乙所有A地及建造於A地上之B屋。甲因其對乙之債權屆期未獲清償，乃向法院聲請拍賣A地，並由丙 拍定。乙之B屋與丙取得之A地間的法律關係如何？', '["視為已有地上權之設定", "視為在B屋得使用期限內，有租賃關係", "推定在B屋得使用期限內，有租賃關係", "丙得請求乙拆除B屋"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 31, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01041', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '下列關於最高限額抵押權之敘述，何者正確？', '["為避免法律關係複雜，最高限額抵押權不得共有", "原債權確定前，抵押權人與抵押人得約定變更其債務人", "最高限額抵押權人得讓與其抵押權次序與後次序抵押權人", "原債權確定前，抵押權人得任意分割最高限額抵押權之一部與他人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01042', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲之兄長乙與丙結婚，丙有兄長丁。關於四人之親系及親等關係，下列敘述，何者錯誤？', '["甲與乙為旁系血親二親等", "乙與丁為旁系姻親二親等", "甲與丙為旁系姻親二親等", "甲與丁為旁系姻親二親等"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL),
  ('real-estate-moex-01043', 'real-estate', 'real-estate-moex-104-a7c7609b', 'sub-real-estate-04', NULL, 'single_choice', '甲男婚外情，甲妻丁得知忿而與甲離婚，並完成登記。甲旋即與乙女於教堂牧師見證下，宣布結為夫妻， 並請鄰近攤販丙、戊於結婚證書上簽名。下列敘述，何者正確？', '["甲、乙婚姻有效成立，因甲、乙有公開之儀式及二人以上之證人", "甲、乙婚姻有效成立，因甲、丁已離婚，且甲、乙有結婚證書", "甲、乙婚姻不成立，因甲不得同時與二人結婚", "甲、乙婚姻不成立，因甲、乙未辦理結婚登記"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:39+00:00", "source_pdf_sha1": "e595e37e06de", "answer_pdf_sha1": "c99d0639b95d", "source_family": "moex-gov-tw", "moex": {"exam_code": "104170", "c": "601", "s": "1104", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "民法概要", "year": "104", "exam_name": "104年專技建築師、技師、第二次食品技師、不動產經紀人、記帳士考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "brokers", "db_exam_id": "real-estate"}'::jsonb, NULL)
